Перепиши данную программу на языке C++ с использованием map ввместо vector. Программа: #include <iostream>
#include <vector>
#include <string>
#include <fstream>
#include <chrono>

using namespace std;
// Прототип фигуры
class Shape {
public:
    virtual void draw() = 0;
    virtual Shape* clone() = 0;
    virtual string typeName() = 0;
};

// Конкретные фигуры
class Circle : public Shape {
public:
    void draw() override {
        cout << "Drawing a Circle" << endl;
    }

    Shape* clone() override {
        return new Circle(*this);
    }

    string typeName() override {
        return "Circle";
    }
};

class Square : public Shape {
public:
    void draw() override {
        cout << "Drawing a Square" << endl;
    }

    Shape* clone() override {
        return new Square(*this);
    }

    string typeName() override {
        return "Square";
    }
};

// Фабрика фигур
class ShapeFactory {
private:
    vector<Shape> shapes;
public:
    Shape* createShape(const string& type) {
        for (auto shape : shapes) {
            if (shape.typeName() == type) {
                return shape.clone();
            }
        }
        Shape* newShape;
        if (type == "Circle") {
            newShape = new Circle(*this);
        }
        else if (type == "Square") {
            newShape = new Square(*this);
        }
        else {
            return nullptr; // Неизвестный тип фигуры
        }
        shapes.push_back(newShape);
        return newShape;
    }
};

// Логгер
class Log {
private:
    ofstream logFile;
    static Log* instance;
    Log() {
        logFile.open("log.txt", ios::app);
    }

public:
    static Log* getInstance() {
        if (instance == nullptr) {
            instance = new Log();
        }
        return instance;
    }

    ~Log() {
        logFile.close();
    }

    void logEvent(const string& event) {
        auto now = chrono::system_clock::now();
        time_t t = chrono::system_clock::to_time_t(now);
        logFile << asctime(localtime(&t)) << ": " << event << endl;
        logFile.flush();
    }
};

Log* Log::instance = nullptr;

int main() {
    ShapeFactory shapeFactory;
    Log* logger = Log::getInstance();

    Shape* circle1 = shapeFactory.createShape("Circle");
    circle1->draw();

    Shape* circle2 = shapeFactory.createShape("Circle");
    circle2->draw();

    Shape* square1 = shapeFactory.createShape("Square");
    square1->draw();

    Shape* square2 = shapeFactory.createShape("Square");
    square2->draw();

    logger->logEvent("Shapes created");

    delete circle1;
    delete circle2;
    delete square1;
    delete square2;

    return 0;
}

